function applyEditableFlag(root: HTMLElement, editing: boolean) {
  root.querySelectorAll<HTMLElement>("[data-editable]").forEach((el) => {
    if (editing) el.setAttribute("contenteditable", "true");
    else el.removeAttribute("contenteditable");
  });
}

function applyListEditControls(root: HTMLElement, editing: boolean, onChange: () => void) {
  const lists = Array.from(root.querySelectorAll("ul.modulo-list"));

  lists.forEach((ul) => {
    ul.querySelectorAll(".row-delete-btn").forEach((el) => el.remove());
    const next = ul.nextElementSibling as HTMLElement | null;
    if (next && next.classList.contains("table-row-controls")) next.remove();

    if (!editing) return;

    const addDeleteButton = (li: HTMLLIElement) => {
      if (li.querySelector(".row-delete-btn")) return;
      const btn = document.createElement("span");
      btn.className = "row-delete-btn no-print";
      btn.textContent = " 🗑";
      btn.contentEditable = "false";
      btn.title = "Remover item";
      btn.addEventListener("click", (e) => {
        e.preventDefault();
        e.stopPropagation();
        li.remove();
        onChange();
      });
      li.appendChild(btn);
    };

    Array.from(ul.querySelectorAll(":scope > li")).forEach((li) => addDeleteButton(li as HTMLLIElement));

    const wrapper = document.createElement("div");
    wrapper.className = "table-row-controls no-print";
    const addBtn = document.createElement("button");
    addBtn.type = "button";
    addBtn.className = "table-add-row-btn";
    addBtn.textContent = "+ Adicionar item";
    addBtn.addEventListener("click", () => {
      const items = Array.from(ul.querySelectorAll(":scope > li"));
      const template = items[items.length - 1] as HTMLLIElement | undefined;
      if (!template) return;
      const newLi = template.cloneNode(true) as HTMLLIElement;
      newLi.querySelectorAll(".row-delete-btn").forEach((el) => el.remove());
      newLi.innerHTML = "<b>Novo item</b> — descrição aqui";
      newLi.setAttribute("data-editable", "");
      newLi.setAttribute("contenteditable", "true");
      ul.appendChild(newLi);
      addDeleteButton(newLi);
      onChange();
    });
    wrapper.appendChild(addBtn);
    ul.insertAdjacentElement("afterend", wrapper);
  });
}

function applyFaseEditControls(root: HTMLElement, editing: boolean, onChange: () => void) {
  const renumber = () => {
    Array.from(root.querySelectorAll(".fase")).forEach((fase, i) => {
      const num = fase.querySelector(".fase-num");
      if (num) num.textContent = String(i + 1);
    });
  };

  const fases = Array.from(root.querySelectorAll(".fase"));
  fases.forEach((fase) => fase.querySelectorAll(".row-delete-btn").forEach((el) => el.remove()));
  const existingControls = root.querySelector(".fase-controls");
  if (existingControls) existingControls.remove();

  if (!editing || fases.length === 0) return;

  const addDeleteButton = (fase: Element) => {
    if (fase.querySelector(".row-delete-btn")) return;
    const btn = document.createElement("span");
    btn.className = "row-delete-btn no-print fase-delete-btn";
    btn.textContent = "🗑";
    btn.contentEditable = "false";
    btn.title = "Remover fase";
    btn.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      fase.remove();
      renumber();
      onChange();
    });
    fase.appendChild(btn);
  };

  fases.forEach((fase) => addDeleteButton(fase));

  const lastFase = fases[fases.length - 1];
  const wrapper = document.createElement("div");
  wrapper.className = "table-row-controls fase-controls no-print";
  const addBtn = document.createElement("button");
  addBtn.type = "button";
  addBtn.className = "table-add-row-btn";
  addBtn.textContent = "+ Adicionar fase";
  addBtn.addEventListener("click", () => {
    const currentFases = Array.from(root.querySelectorAll(".fase"));
    const template = currentFases[currentFases.length - 1];
    if (!template) return;
    const newFase = template.cloneNode(true) as HTMLElement;
    newFase.querySelectorAll(".row-delete-btn").forEach((el) => el.remove());
    const b = newFase.querySelector(".fase-content b");
    const span = newFase.querySelector(".fase-content span");
    if (b) {
      b.textContent = "Nova fase";
      b.setAttribute("data-editable", "");
      b.setAttribute("contenteditable", "true");
    }
    if (span) {
      span.textContent = "Descrição da nova fase";
      span.setAttribute("data-editable", "");
      span.setAttribute("contenteditable", "true");
    }
    template.insertAdjacentElement("afterend", newFase);
    addDeleteButton(newFase);
    renumber();
    onChange();
  });
  wrapper.appendChild(addBtn);
  lastFase.insertAdjacentElement("afterend", wrapper);
}

function applyTableRowControls(root: HTMLElement, editing: boolean, onChange: () => void) {
  const tables = Array.from(root.querySelectorAll("table"));

  tables.forEach((table) => {
    // Clean slate: remove any previously injected controls before re-adding them
    table.querySelectorAll(".row-delete-btn").forEach((el) => el.remove());
    const next = table.nextElementSibling as HTMLElement | null;
    if (next && next.classList.contains("table-row-controls")) next.remove();

    if (!editing) return;

    const tbody = table.querySelector("tbody") || table;

    const addDeleteButton = (row: HTMLTableRowElement) => {
      const lastCell = row.querySelector("td:last-child");
      if (!lastCell || lastCell.querySelector(".row-delete-btn")) return;
      const btn = document.createElement("span");
      btn.className = "row-delete-btn no-print";
      btn.textContent = " 🗑";
      btn.contentEditable = "false";
      btn.title = "Remover linha";
      btn.addEventListener("click", (e) => {
        e.preventDefault();
        e.stopPropagation();
        row.remove();
        onChange();
      });
      lastCell.appendChild(btn);
    };

    Array.from(tbody.querySelectorAll(":scope > tr")).forEach((row) =>
      addDeleteButton(row as HTMLTableRowElement)
    );

    const wrapper = document.createElement("div");
    wrapper.className = "table-row-controls no-print";
    const addBtn = document.createElement("button");
    addBtn.type = "button";
    addBtn.className = "table-add-row-btn";
    addBtn.textContent = "+ Adicionar linha";
    addBtn.addEventListener("click", () => {
      const rows = Array.from(tbody.querySelectorAll(":scope > tr"));
      const templateRow = rows[rows.length - 1] as HTMLTableRowElement | undefined;
      if (!templateRow) return;
      const newRow = templateRow.cloneNode(true) as HTMLTableRowElement;
      newRow.querySelectorAll(".row-delete-btn").forEach((el) => el.remove());
      newRow.querySelectorAll("td").forEach((td) => {
        td.textContent = "Novo item";
        td.setAttribute("data-editable", "");
        td.setAttribute("contenteditable", "true");
      });
      tbody.appendChild(newRow);
      addDeleteButton(newRow);
      onChange();
    });
    wrapper.appendChild(addBtn);
    table.insertAdjacentElement("afterend", wrapper);
  });
}

interface ProposalEditorProps {
  proposalId?: string;
  shareToken?: string;
  mode: "edit" | "view";
}

export default function ProposalEditor({ proposalId, shareToken, mode }: ProposalEditorProps) {
  const navigate = useNavigate();
  const pageRef = useRef<HTMLDivElement>(null);
  const [editing, setEditing] = useState(false);
  const [savedAt, setSavedAt] = useState("");
  const [saving, setSaving] = useState(false);
  const [clientName, setClientName] = useState("");
  const [loading, setLoading] = useState(true);
  const [notFound, setNotFound] = useState(false);
  const [pageHtml, setPageHtml] = useState<string | null>(null);
  const [session, setSession] = useState<any>(undefined);
  const [copied, setCopied] = useState(false);
  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const nameTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const isEdit = mode === "edit";

  useEffect(() => {
    if (!isEdit) return;
    supabase.auth.getSession().then(({ data }) => {
      setSession(data.session);
      if (!data.session) navigate({ to: "/login" });
    });
    const { data: sub } = supabase.auth.onAuthStateChange((_event, s) => {
      setSession(s);
      if (isEdit && !s) navigate({ to: "/login" });
    });
    return () => sub.subscription.unsubscribe();
  }, [isEdit, navigate]);

  useEffect(() => {
    setLoading(true);
    setNotFound(false);
    const load = async () => {
      try {
        if (isEdit && proposalId) {
          const p = await getProposal(proposalId);
          setClientName(p.client_name || "");
          setPageHtml(p.content?.html || DEFAULT_HTML);
        } else if (!isEdit && shareToken) {
          const p = await getProposalByToken(shareToken);
          setClientName(p.client_name || "");
          setPageHtml(p.content?.html || DEFAULT_HTML);
        }
      } catch {
        setNotFound(true);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [isEdit, proposalId, shareToken]);

  // Write the loaded HTML into the page div once both the data AND the DOM node exist
  useEffect(() => {
    if (pageRef.current && pageHtml !== null) {
      // Rebuild the logo/icon <img> tags from scratch at the STRING level before
      // parsing into the DOM. This guarantees a well-formed tag regardless of
      // whatever (possibly corrupted/truncated) markup was previously saved.
      const safeHtml = pageHtml
        .replace(/<img[^>]*class="logo-img"[^>]*>/g, `<img src="${LOGO_SRC}" alt="Nortyx" class="logo-img" />`)
        .replace(/<img[^>]*class="footer-icon"[^>]*>/g, `<img src="${ICON_SRC}" alt="Nortyx" class="footer-icon" />`);
      pageRef.current.innerHTML = safeHtml;
      applyEditableFlag(pageRef.current, editing);
      applyTableRowControls(pageRef.current, editing, scheduleSave);
      applyListEditControls(pageRef.current, editing, scheduleSave);
      applyFaseEditControls(pageRef.current, editing, scheduleSave);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pageHtml]);

  useEffect(() => {
    if (pageRef.current) {
      applyEditableFlag(pageRef.current, editing);
      applyTableRowControls(pageRef.current, editing, scheduleSave);
      applyListEditControls(pageRef.current, editing, scheduleSave);
      applyFaseEditControls(pageRef.current, editing, scheduleSave);
    }
  }, [editing]);

  useEffect(() => {
    if (!isEdit) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.ctrlKey && e.shiftKey && (e.key === "E" || e.key === "e")) {
        e.preventDefault();
        setEditing((v) => !v);
      }
      if (e.ctrlKey && e.key === "s") {
        e.preventDefault();
        saveNow();
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isEdit]);

  const saveNow = async () => {
    if (!isEdit || !proposalId || !pageRef.current) return;
    if (saveTimer.current) clearTimeout(saveTimer.current);
    setSaving(true);
    const clone = pageRef.current.cloneNode(true) as HTMLElement;
    clone.querySelectorAll("[contenteditable]").forEach((el) => el.removeAttribute("contenteditable"));
    clone.querySelectorAll(".row-delete-btn, .table-row-controls").forEach((el) => el.remove());
    try {
      await updateProposalContent(proposalId, clone.innerHTML);
      setSavedAt(new Date().toLocaleTimeString("pt-BR"));
    } catch {
      // ignore transient save errors
    } finally {
      setSaving(false);
    }
  };

  const scheduleSave = () => {
    if (!isEdit || !proposalId) return;
    if (saveTimer.current) clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(saveNow, 800);
  };

  const handleClientNameChange = (value: string) => {
    setClientName(value);
    if (!proposalId) return;
    if (nameTimer.current) clearTimeout(nameTimer.current);
    nameTimer.current = setTimeout(() => {
      updateProposalClientName(proposalId, value).catch(() => {});
    }, 600);
  };

  const handleCopyLink = async () => {
    if (!proposalId) return;
    try {
      const p = await getProposal(proposalId);
      const url = `https://aorviauyrmsfpgovksrm.supabase.co/functions/v1/share-preview?token=${p.share_token}`;
      await navigator.clipboard.writeText(url);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // ignore
    }
  };

  if (notFound) {
    return <div style={{ padding: 40, textAlign: "center", color: "#6b7280" }}>Proposta não encontrada.</div>;
  }

  return (
    <div className="proposal-wrapper">
      {isEdit && (
        <div className="toolbar no-print">
          <input
            value={clientName}
            onChange={(e) => handleClientNameChange(e.target.value)}
            placeholder="Nome do cliente"
            style={{ padding: "8px 12px", border: "1px solid #e2e5ea", borderRadius: 6, fontSize: 13, minWidth: 180 }}
          />
          <button
            className={`btn ${editing ? "btn-active" : ""}`}
            onClick={() => setEditing((v) => !v)}
            title="Ctrl+Shift+E"
          >
            {editing ? "✓ Editando" : "✎ Editar texto"}
          </button>
          <button className="btn" onClick={saveNow} title="Ctrl+S" disabled={saving}>
            {saving ? "Salvando..." : "💾 Salvar agora"}
          </button>
          <button className="btn" onClick={() => window.print()}>🖨 Imprimir / PDF</button>
          <button className="btn btn-ghost" onClick={handleCopyLink}>
            {copied ? "✓ Link copiado!" : "🔗 Copiar link do cliente"}
          </button>
          <span className="save-status">{savedAt ? `Salvo às ${savedAt}` : "Autosave ativo"}</span>
        </div>
      )}

      {loading && (
        <div style={{ padding: "10px 0", textAlign: "center", color: "#6b7280", fontSize: 13 }}>
          Carregando proposta...
        </div>
      )}

      <div
        className="page"
        ref={pageRef}
        onInput={scheduleSave}
        suppressContentEditableWarning
      />

      {isEdit && editing && <div className="edit-hint no-print">Modo edição · Ctrl+Shift+E para sair</div>}
    </div>
  );
}
